import { castRow, castRows, type DatabaseClient } from "@/lib/data/shared";
import type {
  ConnectionRecord,
  ThreadListItem,
  ThreadRecord,
} from "@/lib/types";

export const threadSelect = [
  "id",
  "user_id",
  "character_id",
  "connection_id",
  "model_id",
  "persona_id",
  "active_branch_id",
  "title",
  "is_title_autogenerated",
  "status",
  "archived_at",
  "pinned_at",
  "temperature_override",
  "top_p_override",
  "max_output_tokens_override",
  "created_at",
  "updated_at",
].join(", ");

type ThreadLibraryRow = ThreadRecord & {
  character_name: string | null;
  persona_name: string | null;
};

function normalizeThreadLibraryRows(rows: unknown[]) {
  return castRows<ThreadLibraryRow>(rows, "Thread library rows").map(
    ({ character_name, persona_name, ...thread }) =>
      ({
        ...thread,
        characters: character_name ? { name: character_name } : null,
        user_personas: persona_name ? { name: persona_name } : null,
      }) satisfies ThreadListItem,
  );
}

async function searchThreadLibrary(
  supabase: DatabaseClient,
  userId: string,
  options?: {
    query?: string;
    status?: "active" | "archived" | "all";
    limit?: number;
  },
) {
  const { data, error } = await supabase.rpc("search_thread_library", {
    p_user_id: userId,
    p_query: options?.query?.trim() || null,
    p_status: options?.status ?? "all",
    p_limit: options?.limit ?? null,
  });

  if (error) throw error;
  return normalizeThreadLibraryRows(data ?? []);
}

export async function listThreads(supabase: DatabaseClient, userId: string) {
  return listThreadItems(supabase, userId, { status: "active" });
}

export async function listRecentThreads(
  supabase: DatabaseClient,
  userId: string,
  limit = 6,
) {
  return searchThreadLibrary(supabase, userId, {
    status: "active",
    limit,
  });
}

export async function listThreadItems(
  supabase: DatabaseClient,
  userId: string,
  options?: {
    query?: string;
    status?: "active" | "archived" | "all";
  },
) {
  return searchThreadLibrary(supabase, userId, {
    query: options?.query,
    status: options?.status ?? "all",
  });
}

export async function getThread(
  supabase: DatabaseClient,
  userId: string,
  threadId: string,
) {
  const { data, error } = await supabase
    .from("chat_threads")
    .select(threadSelect)
    .eq("user_id", userId)
    .eq("id", threadId)
    .maybeSingle();

  if (error) throw error;
  return data ? castRow<ThreadRecord>(data) : null;
}

export async function createThread(
  supabase: DatabaseClient,
  userId: string,
  args: {
    characterId: string;
    connection: ConnectionRecord;
    modelId: string;
    title: string;
    personaId: string;
  },
) {
  const { data, error } = await supabase.rpc("create_thread_with_main_branch", {
    p_user_id: userId,
    p_character_id: args.characterId,
    p_connection_id: args.connection.id,
    p_model_id: args.modelId,
    p_persona_id: args.personaId,
    p_title: args.title,
  });

  if (error) throw error;
  return castRow<ThreadRecord>(data, "Created thread");
}

export async function updateThreadModel(
  supabase: DatabaseClient,
  userId: string,
  args: { threadId: string; connectionId: string; modelId: string },
) {
  const { data, error } = await supabase
    .from("chat_threads")
    .update({
      connection_id: args.connectionId,
      model_id: args.modelId,
    })
    .eq("id", args.threadId)
    .eq("user_id", userId)
    .select(threadSelect)
    .single();

  if (error) throw error;
  return castRow<ThreadRecord>(data);
}

export async function updateThreadPersona(
  supabase: DatabaseClient,
  userId: string,
  args: { threadId: string; personaId: string },
) {
  const { data, error } = await supabase
    .from("chat_threads")
    .update({ persona_id: args.personaId })
    .eq("id", args.threadId)
    .eq("user_id", userId)
    .select(threadSelect)
    .single();

  if (error) throw error;
  return castRow<ThreadRecord>(data);
}

export async function switchActiveBranch(
  supabase: DatabaseClient,
  userId: string,
  args: { threadId: string; branchId: string },
) {
  // Verify the branch belongs to the target thread before switching
  const { data: branch, error: branchError } = await supabase
    .from("chat_branches")
    .select("id")
    .eq("id", args.branchId)
    .eq("thread_id", args.threadId)
    .maybeSingle();

  if (branchError) throw branchError;
  if (!branch) {
    throw new Error(
      `Branch ${args.branchId} does not belong to thread ${args.threadId}.`,
    );
  }

  const { data, error } = await supabase
    .from("chat_threads")
    .update({ active_branch_id: args.branchId })
    .eq("id", args.threadId)
    .eq("user_id", userId)
    .select(threadSelect)
    .single();

  if (error) throw error;
  return castRow<ThreadRecord>(data);
}

export async function renameThread(
  supabase: DatabaseClient,
  userId: string,
  threadId: string,
  title: string,
) {
  const { error } = await supabase
    .from("chat_threads")
    .update({
      title,
      is_title_autogenerated: false,
      updated_at: new Date().toISOString(),
    })
    .eq("id", threadId)
    .eq("user_id", userId);

  if (error) throw error;
  return getThread(supabase, userId, threadId);
}

export async function updateThreadPinnedState(
  supabase: DatabaseClient,
  userId: string,
  args: { threadId: string; pinned: boolean },
) {
  const { data, error } = await supabase
    .from("chat_threads")
    .update({
      pinned_at: args.pinned ? new Date().toISOString() : null,
      updated_at: new Date().toISOString(),
    })
    .eq("id", args.threadId)
    .eq("user_id", userId)
    .select(threadSelect)
    .single();

  if (error) throw error;
  return castRow<ThreadRecord>(data);
}

export async function updateThreadStatus(
  supabase: DatabaseClient,
  userId: string,
  args: { threadId: string; status: ThreadRecord["status"] },
) {
  const archivedAt = args.status === "archived" ? new Date().toISOString() : null;
  const { data, error } = await supabase
    .from("chat_threads")
    .update({
      status: args.status,
      archived_at: archivedAt,
      updated_at: new Date().toISOString(),
    })
    .eq("id", args.threadId)
    .eq("user_id", userId)
    .select(threadSelect)
    .single();

  if (error) throw error;
  return castRow<ThreadRecord>(data);
}

export async function deleteThread(
  supabase: DatabaseClient,
  userId: string,
  threadId: string,
) {
  const { error } = await supabase
    .from("chat_threads")
    .delete()
    .eq("id", threadId)
    .eq("user_id", userId);

  if (error) throw error;
}
